    public static Optional<ThreadHeartbeatSubjectParts> parseThreadHeartbeatSubject(String subject) {
        List<String> patternTokens = List.of("dd", "remote", "thread", "{thread_id}", "heartbeat");
        String[] subjectTokens = subject.split("\\.");
        if (patternTokens.size() != subjectTokens.length) return Optional.empty();
        String threadId = null;
        for (int i = 0; i < patternTokens.size(); i += 1) {
            String p = patternTokens.get(i);
            String s = subjectTokens[i];
            if (p.startsWith("{") && p.endsWith("}")) {
                String name = p.substring(1, p.length() - 1);
                switch (name) {
                    case "thread_id" -> threadId = s;
                    default -> { return Optional.empty(); }
                }
            } else if (!p.equals(s)) {
                return Optional.empty();
            }
        }
        return Optional.of(new ThreadHeartbeatSubjectParts(threadId));
    }

